draw(A--B--C--cycle);
xaxis(-2,14,Arrows(4));
yaxis(-1,7,Arrows(4));
label("$(0,0)$",A,SW);
label("$(x,0)$",B,S);
label("$(x,5)$",C,N);[/asy]

